  if (events.length === 0) {
    return (
      <View style={styles.centered}>
        <Text style={styles.emptyText}>No events for this session.</Text>
      </View>
    );
  }

  return (
    <ScrollView style={styles.container}>
      {events.map((event) => (
        <EventItem key={event.id} event={event} />
      ))}
    </ScrollView>
  );
}

