    borderBottomColor: "#e5e7eb",
    paddingVertical: 8,
    paddingHorizontal: 8,
  },
  headerCell: {
    width: CELL_WIDTH,
    fontSize: 12,
    fontWeight: "700",
    color: "#6b7280",
