    17→  Notification: "◆",
    18→  Setup: "⚙",
    19→  SubagentStart: "▷",
    20→  SubagentStop: "◁",
    21→  PermissionRequest: "?",
    22→  PreCompact: "⌃",
    23→};
    24→
    25→const EVENT_COLOR: Record<string, string> = {
    26→  PreToolUse: "#3b82f6",
    27→  PostToolUse: "#22c55e",
    28→  PostToolUseFailure: "#ef4444",
    29→  SessionStart: "#8b5cf6",
    30→  SessionEnd: "#8b5cf6",
