    37→
    38→function fmt(iso: string): string {
    39→  const d = new Date(iso);
    40→  const hh = String(d.getHours()).padStart(2, "0");
    41→  const min = String(d.getMinutes()).padStart(2, "0");
    42→  const ss = String(d.getSeconds()).padStart(2, "0");
    43→  return `${hh}:${min}:${ss}`;
    44→}
    45→
    46→function getToolName(data: unknown): string | undefined {
    47→  if (data && typeof data === "object") {
    48→    const d = data as Record<string, unknown>;
    49→    if (typeof d.tool_name === "string") return d.tool_name;
    50→  }
    51→  return undefined;
    52→}
    53→
    54→function getMessage(data: unknown): string | undefined {
    55→  if (data && typeof data === "object") {
    56→    const d = data as Record<string, unknown>;
    57→    if (typeof d.last_assistant_message === "string") return d.last_assistant_message;
    58→    if (typeof d.message === "string") return d.message;
    59→    if (typeof d.prompt === "string") return d.prompt;
    60→  }
    61→  return undefined;
    62→}
    63→
    64→function getToolInput(data: unknown): string | undefined {
    65→  if (data && typeof data === "object") {
    66→    const d = data as Record<string, unknown>;
    67→    if (d.tool_input !== undefined) {
    68→      const s = JSON.stringify(d.tool_input, null, 2);
    69→      return s.length > 800 ? s.slice(0, 800) + "\n…" : s;
    70→    }
    71→  }
    72→  return undefined;
    73→}
    74→
    75→export function EventItem({ event }: Props) {
