        failed: post?.event === "PostToolUseFailure",
      });
      continue;
    }

    result.push({ kind: "event", event });
  }

  return result;
}

function itemKey(item: DisplayItem): string {
  return item.kind === "toolUse" ? `tool-${item.pre.id}` : `evt-${item.event.id}`;
}

// ─── Screen ───────────────────────────────────────────────────────────────────

export function SessionDetail({ route, navigation }: Props) {
  const { sessionId } = route.params;
  const [session, setSession] = useState<Session | null>(null);
  const [items, setItems] = useState<DisplayItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    Promise.all([fetchSession(sessionId), fetchSessionEvents(sessionId)])
      .then(([s, evs]) => {
        setSession(s);
        setItems(groupEvents(evs));
        setError(null);
      })
      .catch((err: unknown) => setError(String(err)))
      .finally(() => setLoading(false));
  }, [sessionId]);

  if (loading) {
    return (
      <View style={styles.centered}>
        <ActivityIndicator size="large" color="#6366f1" />
      </View>
    );
  }

  if (error) {
    return (
      <View style={styles.centered}>
        <Text style={styles.errorText}>{error}</Text>
      </View>
    );
  }

  const renderItem: ListRenderItem<DisplayItem> = ({ item }) => {
    if (item.kind === "toolUse") {
      return <ToolUseItem pre={item.pre} post={item.post} failed={item.failed} />;
    }
    return <EventItem event={item.event} />;
  };

  const header = session?.parentSessionId ? (
    <TouchableOpacity
      style={styles.parentBanner}
      onPress={() =>
        navigation.push("SessionDetail", {
          sessionId: session.parentSessionId!,
          title: session.parentSessionId!.slice(0, 8) + "…",
        })
      }
    >
      <Text style={styles.parentLabel}>↑ Continuation of</Text>
      <Text style={styles.parentId}>{session.parentSessionId.slice(0, 8)}…</Text>
    </TouchableOpacity>
  ) : null;

  return (
    <FlatList
      style={styles.list}
      data={items}
      keyExtractor={itemKey}
      renderItem={renderItem}
      ListHeaderComponent={header}
      ListEmptyComponent={
        <View style={styles.centered}>
          <Text style={styles.emptyText}>No events for this session.</Text>
        </View>
      }
    />
  );
}

