import React, { useEffect, useState } from "react";
import {
  View,
  Text,
  FlatList,
  StyleSheet,
  ActivityIndicator,
  TouchableOpacity,
  type ListRenderItem,
} from "react-native";
import type { StackScreenProps } from "@react-navigation/stack";
import type { RootStackParamList } from "../../App";
import { fetchSession, fetchSessionEvents, type Session, type Event } from "../api";
import { EventItem } from "../components/EventItem";
import { ToolUseItem } from "../components/ToolUseItem";

type Props = StackScreenProps<RootStackParamList, "SessionDetail">;

// ─── Event grouping ───────────────────────────────────────────────────────────

type DisplayItem =
  | { kind: "event"; event: Event }
  | { kind: "toolUse"; pre: Event; post?: Event; failed: boolean };

function groupEvents(events: Event[]): DisplayItem[] {
  // Pre-build a lookup of tool_use_id → PostToolUse/PostToolUseFailure event
  const postMap = new Map<string, Event>();
  for (const event of events) {
    if (event.event === "PostToolUse" || event.event === "PostToolUseFailure") {
      const d = event.data as Record<string, unknown>;
      const id = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
      if (id) postMap.set(id, event);
    }
  }

  const result: DisplayItem[] = [];
  const consumed = new Set<number>(); // event.id of PostToolUse events merged at Pre position

  for (const event of events) {
    // Skip PostToolUse events that were already merged at their Pre position
    if (
      (event.event === "PostToolUse" || event.event === "PostToolUseFailure") &&
      consumed.has(event.id)
    ) {
      continue;
    }

    if (event.event === "PreToolUse") {
      const d = event.data as Record<string, unknown>;
      const toolUseId = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
      const post = toolUseId ? postMap.get(toolUseId) : undefined;
      if (post) consumed.add(post.id);
      result.push({
        kind: "toolUse",
        pre: event,
        post,
        failed: post?.event === "PostToolUseFailure",
      });
      continue;
    }

    result.push({ kind: "event", event });
  }

  return result;
}

function itemKey(item: DisplayItem): string {
  return item.kind === "toolUse" ? `tool-${item.pre.id}` : `evt-${item.event.id}`;
}

// ─── Screen ───────────────────────────────────────────────────────────────────

export function SessionDetail({ route, navigation }: Props) {
  const { sessionId } = route.params;
  const [session, setSession] = useState<Session | null>(null);
  const [items, setItems] = useState<DisplayItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    Promise.all([fetchSession(sessionId), fetchSessionEvents(sessionId)])
      .then(([s, evs]) => {
        setSession(s);
        setItems(groupEvents(evs));
        setError(null);
      })
      .catch((err: unknown) => setError(String(err)))
      .finally(() => setLoading(false));
  }, [sessionId]);

  if (loading) {
    return (
      <View style={styles.centered}>
        <ActivityIndicator size="large" color="#6366f1" />
      </View>
    );
  }

  if (error) {
    return (
      <View style={styles.centered}>
        <Text style={styles.errorText}>{error}</Text>
      </View>
    );
  }

  const renderItem: ListRenderItem<DisplayItem> = ({ item }) => {
    if (item.kind === "toolUse") {
      return <ToolUseItem pre={item.pre} post={item.post} failed={item.failed} />;
    }
    return <EventItem event={item.event} />;
  };

  const header = session?.parentSessionId ? (
    <TouchableOpacity
      style={styles.parentBanner}
      onPress={() =>
        navigation.push("SessionDetail", {
          sessionId: session.parentSessionId!,
          title: session.parentSessionId!.slice(0, 8) + "…",
        })
      }
    >
      <Text style={styles.parentLabel}>↑ Continuation of</Text>
      <Text style={styles.parentId}>{session.parentSessionId.slice(0, 8)}…</Text>
    </TouchableOpacity>
  ) : null;

  return (
    <FlatList
      style={styles.list}
      data={items}
      keyExtractor={itemKey}
      renderItem={renderItem}
      ListHeaderComponent={header}
      ListEmptyComponent={
        <View style={styles.centered}>
          <Text style={styles.emptyText}>No events for this session.</Text>
        </View>
      }
    />
  );
}

const styles = StyleSheet.create({
  list: {
    flex: 1,
    backgroundColor: "#fff",
  },
  centered: {
    flex: 1,
    alignItems: "center",
    justifyContent: "center",
    padding: 24,
    minHeight: 120,
  },
  parentBanner: {
    flexDirection: "row",
    alignItems: "center",
    gap: 6,
    backgroundColor: "#f0f9ff",
    borderBottomWidth: 1,
    borderBottomColor: "#bae6fd",
    paddingHorizontal: 14,
    paddingVertical: 8,
  },
  parentLabel: {
    fontSize: 12,
    color: "#0369a1",
  },
  parentId: {
    fontSize: 12,
    color: "#0369a1",
    fontFamily: "monospace",
    fontWeight: "600",
    textDecorationLine: "underline",
