    color: "#fff",
    fontSize: 10,
    fontWeight: "bold",
  },
  expandHint: {
    fontSize: 10,
    color: "#9ca3af",
  },
  bodyText: {
    marginTop: 4,
    fontSize: 13,
    color: "#6b7280",
    fontStyle: "italic",
    lineHeight: 18,
  },
  codeBlock: {
    marginTop: 6,
