    18→
    19→// ─── Event grouping ───────────────────────────────────────────────────────────
    20→
    21→type DisplayItem =
    22→  | { kind: "event"; event: Event }
    23→  | { kind: "toolUse"; pre: Event; post?: Event; failed: boolean };
    24→
    25→function groupEvents(events: Event[]): DisplayItem[] {
    26→  const postMap = new Map<string, Event>();
    27→  for (const event of events) {
    28→    if (event.event === "PostToolUse" || event.event === "PostToolUseFailure") {
    29→      const d = event.data as Record<string, unknown>;
    30→      const id = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
    31→      if (id) postMap.set(id, event);
    32→    }
    33→  }
    34→
    35→  const result: DisplayItem[] = [];
    36→  const consumed = new Set<number>();
    37→
    38→  for (const event of events) {
    39→    if (
    40→      (event.event === "PostToolUse" || event.event === "PostToolUseFailure") &&
    41→      consumed.has(event.id)
    42→    ) {
    43→      continue;
    44→    }
    45→
    46→    if (event.event === "PreToolUse") {
    47→      const d = event.data as Record<string, unknown>;
    48→      const toolUseId = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
    49→      const post = toolUseId ? postMap.get(toolUseId) : undefined;
    50→      if (post) consumed.add(post.id);
    51→      result.push({ kind: "toolUse", pre: event, post, failed: post?.event === "PostToolUseFailure" });
    52→      continue;
    53→    }
    54→
    55→    result.push({ kind: "event", event });
    56→  }
    57→
    58→  return result;
    59→}
    60→
    61→// ─── Screen ───────────────────────────────────────────────────────────────────
