    81→      .catch((err: unknown) => setError(String(err)))
    82→      .finally(() => setLoading(false));
    83→  }, [sessionId]);
    84→
    85→  if (loading) {
    86→    return (
    87→      <View style={styles.centered}>
    88→        <ActivityIndicator size="large" color="#6366f1" />
