   105→          style={styles.parentBanner}
   106→          onPress={() =>
   107→            navigation.push("SessionDetail", {
   108→              sessionId: session.parentSessionId!,
   109→              title: session.parentSessionId!.slice(0, 8) + "…",
   110→            })
   111→          }
   112→        >
