    fontWeight: "600",
    color: "#374151",
    flexShrink: 0,
  },
  summary: {
    fontSize: 11,
    color: "#6b7280",
    fontFamily: "monospace",
    flex: 1,
  },
  time: {
    fontSize: 10,
    color: "#9ca3af",
    flexShrink: 0,
  },
  blockedBadge: {
    backgroundColor: "#ef4444",
    borderRadius: 3,
    paddingHorizontal: 4,
    paddingVertical: 1,
  },
  blockedText: {
    color: "#fff",
    fontSize: 9,
    fontWeight: "bold",
  },
  chevron: {
    fontSize: 9,
    color: "#9ca3af",
    flexShrink: 0,
  },
  items: {
    borderTopWidth: 1,
    borderTopColor: "#e5e7eb",
